namespace sv_5f875827265f4f3d9836c733af03764e.Services;

public class WarehouseStateService : IDisposable
{
    private string _currentWarehouseId = "WH-001";
    private string _currentWarehouseName = "Warehouse A";

    public string CurrentWarehouseId => _currentWarehouseId;
    public string CurrentWarehouseName => _currentWarehouseName;

    public event Action? OnWarehouseChanged;

    public static readonly Dictionary<string, string> AvailableWarehouses = new()
    {
        ["WH-001"] = "Warehouse A",
        ["WH-002"] = "Warehouse B",
        ["WH-003"] = "Warehouse C",
        ["WH-004"] = "Warehouse D"
    };

    public void SetWarehouse(string warehouseId)
    {
        if (!AvailableWarehouses.TryGetValue(warehouseId, out var name))
            return;

        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        _currentWarehouseName = name;
        OnWarehouseChanged?.Invoke();
    }

    public void Dispose()
    {
        OnWarehouseChanged = null;
    }
}

namespace sv_5f875827265f4f3d9836c733af03764e.Services;

public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private CancellationTokenSource? _pollCts;
    private int _subscriberCount;
    private int _currentLowStockCount;

    public int CurrentLowStockCount => _currentLowStockCount;

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnWarehouseChanged += HandleWarehouseChanged;
    }

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _pollCts = new CancellationTokenSource();
            _ = PollLoopAsync(_pollCts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _pollCts?.Cancel();
            _pollCts?.Dispose();
            _pollCts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await RefreshAlertCountAsync();
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task RefreshAlertCountAsync()
    {
        _currentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async void HandleWarehouseChanged()
    {
        // Immediately refresh when warehouse changes
        await RefreshAlertCountAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnWarehouseChanged -= HandleWarehouseChanged;
        _pollCts?.Cancel();
        _pollCts?.Dispose();
        OnAlertCountChanged = null;
    }
}

